189	template<typename T>
190	struct list
191	{
192	    typedef iter_list<T> iterator;
193	
194	    list()
195	    {
196	        head_ = new node<T>();
197	        tail_ = head_;
198	        count_ = 0;
199	    }
200	    ~list()
201	    {
202	        clear();
203	        delete head_;
204	    }
205	    list(const list& l)
206	    {
207	        head_ = new node<T>();
208	        tail_ = head_;
209	        count_ = 0;
210	
211	        for (iter_list<T> i = l.begin(); i != l.end(); ++i)
212	        {
213	            push_back(*i);
214	        }
215	    }
216	
217	    list& operator=(const list& l)
218	    {
219	        if (this == &l)
220	        {
221	            return *this;
222	        }
223	        clear();
224	
225	        for (iter_list<T> i = l.begin(); i != l.end(); ++i)
226	        {
227	            push_back(*i);
228	        }
229	        return *this;
230	    }
231	
232	    void clear()
233	    {
234	        while (count_ > 0)
235	        {
236	            pop_front();
237	        }
238	    }
239	
240	    void pop_front()
241	    {
242	        if (count_ > 0)
243	        {
244	            head_ = head_->next_;
245	            delete head_->prev_;
246	            head_->prev_ = nullptr;
247	            --count_;
248	        }
249	    }
250	
251	    size_t size() const
252	    {
253	        return count_;
254	    }
255	    iter_list<T> begin() const
256	    {
257	        return iter_list<T>(head_);
258	    }
259	    iter_list<T> end() const
260	    {
261	        return iter_list<T>(tail_);
262	    }
263	    bool empty() const
264	    {
265	        return count_ == 0;
266	    }
267	
268	    void push_back(const T& t)
269	    {
270	        if (count_ == 0)
271	        {
272	            head_ = new node<T>(t);
273	            head_->prev_ = nullptr;
274	            head_->next_ = tail_;
275	            tail_->prev_ = head_;
276	            count_ = 1;
277	        }
278	        else
279	        {
280	            node<T>* temp = new node<T>(t);
281	            temp->prev_ = tail_->prev_;
282	            temp->next_ = tail_;
283	            tail_->prev_->next_ = temp;
284	            tail_->prev_ = temp;
285	            ++count_;
286	        }
287	    }
288	
289	    iter_list<T> erase(iter_list<T> pos)
290	    {
291	        if (pos != end())
292	        {
293	            node<T>* temp = pos.curr_;
294	            if (temp == head_)
295	            {
296	                ++pos;
297	                temp->next_->prev_ = nullptr;
298	                head_ = temp->next_;
299	            }
300	            else
301	            {
302	                --pos;
303	                temp->next_->prev_ = temp->prev_;
304	                temp->prev_->next_ = temp->next_;
305	                ++pos;
306	            }
307	            delete temp;
308	            --count_;
309	        }
310	        return pos;
311	    }
312	
313	protected:
314	    node<T>* head_;
315	    node<T>* tail_;
316	    size_t count_;
317	};
