338	void partial_sort(RandomAccessIter first, RandomAccessIter middle, RandomAccessIter last, Compare comp)
339	{
340	    // [TODO] heap sort should be used here, but we simply use bubble sort now
341	    for (auto i = first; i < middle; ++i)
342	    {
343	        // bubble sort
344	        for (auto j = last - 1; j > first; --j)
345	        {
346	            if (comp(*j, *(j - 1)))
347	            {
348	                swap(*j, *(j - 1));
349	            }
350	        }
351	    }
