354	template<typename T>
355	struct vector
356	{
357	    vector()
358	    {
359	    }
360	    vector(const size_t new_size, const T& value = T())
361	    {
362	        resize(new_size, value);
363	    }
364	    ~vector()
365	    {
366	        clear();
367	    }
368	    vector(const vector& v)
369	    {
370	        resize(v.size());
371	        for (size_t i = 0; i < size_; i++)
372	        {
373	            data_[i] = v.data_[i];
374	        }
375	    }
376	
377	    vector& operator=(const vector& v)
378	    {
379	        if (this == &v)
380	        {
381	            return *this;
382	        }
383	        resize(0);
384	        resize(v.size());
385	        for (size_t i = 0; i < size_; i++)
386	        {
387	            data_[i] = v.data_[i];
388	        }
389	        return *this;
390	    }
391	
392	    void resize(const size_t new_size, const T& value = T())
393	    {
394	        try_alloc(new_size);
395	        if (new_size > size_)
396	        {
397	            for (size_t i = size_; i < new_size; i++)
398	            {
399	                new (&data_[i]) T(value);
400	            }
401	        }
402	        else if (new_size < size_)
403	        {
404	            for (size_t i = new_size; i < size_; i++)
405	            {
406	                data_[i].~T();
407	            }
408	        }
409	        size_ = new_size;
410	    }
411	
412	    void clear()
413	    {
414	        for (size_t i = 0; i < size_; i++)
415	        {
416	            data_[i].~T();
417	        }
418	        delete[](char*) data_;
419	        data_ = nullptr;
420	        size_ = 0;
421	        capacity_ = 0;
422	    }
423	
424	    T* data() const
425	    {
426	        return data_;
427	    }
428	    size_t size() const
429	    {
430	        return size_;
431	    }
432	    T& operator[](size_t i) const
433	    {
434	        return data_[i];
435	    }
436	    T* begin() const
437	    {
438	        return &data_[0];
439	    }
440	    T* end() const
441	    {
442	        return &data_[size_];
443	    }
444	    bool empty() const
445	    {
446	        return size_ == 0;
447	    }
448	
449	    void push_back(const T& t)
450	    {
451	        try_alloc(size_ + 1);
452	        new (&data_[size_]) T(t);
453	        size_++;
454	    }
455	
456	    void insert(T* pos, T* b, T* e)
457	    {
458	        vector* v = nullptr;
459	        if (b >= begin() && b < end())
460	        {
461	            //the same vector
462	            v = new vector(*this);
463	            b = v->begin() + (b - begin());
464	            e = v->begin() + (e - begin());
465	        }
466	        size_t diff = pos - begin();
467	        try_alloc(size_ + (e - b));
468	        pos = begin() + diff;
469	        memmove(pos + (e - b), pos, (end() - pos) * sizeof(T));
470	        size_t len = e - b;
471	        size_ += len;
472	        for (size_t i = 0; i < len; i++)
473	        {
474	            *pos = *b;
475	            pos++;
476	            b++;
477	        }
478	        delete v;
479	    }
480	
481	    T* erase(T* pos)
482	    {
483	        pos->~T();
484	        memmove(pos, pos + 1, (end() - pos - 1) * sizeof(T));
485	        size_--;
486	        return pos;
487	    }
488	
489	protected:
490	    T* data_ = nullptr;
491	    size_t size_ = 0;
492	    size_t capacity_ = 0;
493	    void try_alloc(size_t new_size)
494	    {
495	        if (new_size * 3 / 2 > capacity_ / 2)
496	        {
497	            capacity_ = new_size * 2;
498	            T* new_data = (T*)new char[capacity_ * sizeof(T)];
499	            memset(new_data, 0, capacity_ * sizeof(T));
500	            if (data_)
501	            {
502	                memmove(new_data, data_, sizeof(T) * size_);
503	                delete[](char*) data_;
504	            }
505	            data_ = new_data;
506	        }
507	    }
508	};
