523	        return (const char*)data_;
524	    }
525	    bool operator==(const string& str2) const
526	    {
527	        return strcmp(data_, str2.data_) == 0;
528	    }
529	    bool operator==(const char* str2) const
530	    {
531	        return strcmp(data_, str2) == 0;
532	    }
533	    bool operator!=(const char* str2) const
534	    {
535	        return strcmp(data_, str2) != 0;
536	    }
537	    string& operator+=(const string& str1)
538	    {
539	        insert(end(), str1.begin(), str1.end());
540	        return *this;
541	    }
