28	namespace ncnn {
29	
30	// the alignment of all the allocated buffers
31	#define MALLOC_ALIGN    16
32	
33	// Aligns a pointer to the specified number of bytes
34	// ptr Aligned pointer
35	// n Alignment size that must be a power of two
36	template<typename _Tp> static inline _Tp* alignPtr(_Tp* ptr, int n=(int)sizeof(_Tp))
37	{
38	    return (_Tp*)(((size_t)ptr + n-1) & -n);
39	}
40	
41	// exchange-add operation for atomic operations on reference counters
42	#if defined __INTEL_COMPILER && !(defined WIN32 || defined _WIN32)
43	// atomic increment on the linux version of the Intel(tm) compiler
44	#  define NCNN_XADD(addr, delta) (int)_InterlockedExchangeAdd(const_cast<void*>(reinterpret_cast<volatile void*>(addr)), delta)
45	#elif defined __GNUC__
46	#  if defined __clang__ && __clang_major__ >= 3 && !defined __ANDROID__ && !defined __EMSCRIPTEN__ && !defined(__CUDACC__)
47	#    ifdef __ATOMIC_ACQ_REL
48	#      define NCNN_XADD(addr, delta) __c11_atomic_fetch_add((_Atomic(int)*)(addr), delta, __ATOMIC_ACQ_REL)
49	#    else
50	#      define NCNN_XADD(addr, delta) __atomic_fetch_add((_Atomic(int)*)(addr), delta, 4)
51	#    endif
52	#  else
53	#    if defined __ATOMIC_ACQ_REL && !defined __clang__
54	// version for gcc >= 4.7
55	#      define NCNN_XADD(addr, delta) (int)__atomic_fetch_add((unsigned*)(addr), (unsigned)(delta), __ATOMIC_ACQ_REL)
56	#    else
57	#      define NCNN_XADD(addr, delta) (int)__sync_fetch_and_add((unsigned*)(addr), (unsigned)(delta))
58	#    endif
59	#  endif
60	#elif defined _MSC_VER && !defined RC_INVOKED
61	#  include <intrin.h>
62	#  define NCNN_XADD(addr, delta) (int)_InterlockedExchangeAdd((long volatile*)addr, delta)
63	#else
64	// thread-unsafe branch
65	static inline int NCNN_XADD(int* addr, int delta) { int tmp = *addr; *addr += delta; return tmp; }
66	#endif
67	
68	
69	// Aligns a buffer size to the specified number of bytes
70	// The function returns the minimum number that is greater or equal to sz and is divisible by n
71	// sz Buffer size to align
72	// n Alignment size that must be a power of two
73	static inline unsigned int alignSize(unsigned int sz, int n)
74	{
75	    return (sz + n-1) & -n;
76	}
77	
78	static inline void* fastMalloc(unsigned int size)
79	{
80	    unsigned char* udata = (unsigned char*)malloc(size + sizeof(void*) + MALLOC_ALIGN);
81	    if (!udata)
82	        return 0;
83	    unsigned char** adata = alignPtr((unsigned char**)udata + 1, MALLOC_ALIGN);
84	    adata[-1] = udata;
85	    return adata;
86	}
87	
88	
89	static inline void fastFree(void* ptr)
90	{
91	    if (ptr)
92	    {
93	        unsigned char* udata = ((unsigned char**)ptr)[-1];
94	        free(udata);
95	    }
96	}
97	
98	class Allocator
99	{
100	public:
101	    virtual ~Allocator() = 0;
102	    virtual void* fastMalloc(size_t size) = 0;
103	    virtual void fastFree(void* ptr) = 0;
104	};
105	
106	// the three dimension matrix
107	class Mat
108	{
109	public:
110	    // empty
111	    Mat();
112	    // vec
113	    Mat(int w, size_t elemsize = 4u, Allocator* allocator = 0);
114	    // image
115	    Mat(int w, int h, size_t elemsize = 4u, Allocator* allocator = 0);
116	    // dim
117	    Mat(int w, int h, int c, size_t elemsize = 4u, Allocator* allocator = 0);
118	    // copy
119	    Mat(const Mat& m);
120	    // external vec
121	    Mat(int w, void* data, size_t elemsize = 4u, Allocator* allocator = 0);
122	    // external image
123	    Mat(int w, int h, void* data, size_t elemsize = 4u, Allocator* allocator = 0);
124	    // external dim
125	    Mat(int w, int h, int c, void* data, size_t elemsize = 4u, Allocator* allocator = 0);
126	    // release
127	    ~Mat();
128	    // assign
129	    Mat& operator=(const Mat& m);
130	
131	    // deep copy
132	    Mat clone(Allocator* allocator = 0) const;
133	
134	    // allocate vec
135	    void create(int w, size_t elemsize = 4u, Allocator* allocator = 0);
136	    // allocate image
137	    void create(int w, int h, size_t elemsize = 4u, Allocator* allocator = 0);
138	    // allocate dim
139	    void create(int w, int h, int c, size_t elemsize = 4u, Allocator* allocator = 0);
140	    // refcount++
141	    void addref();
142	    // refcount--
143	    void release();
144	
145	    bool empty() const;
146	    size_t total() const;
147	
148	    // data reference
149	    Mat channel(int c);
150	    const Mat channel(int c) const;
151	    float* row(int y);
152	    const float* row(int y) const;
153	    template<typename T> T* row(int y);
154	    template<typename T> const T* row(int y) const;
155	
156	    // range reference
157	    Mat channel_range(int c, int channels);
158	    const Mat channel_range(int c, int channels) const;
159	    Mat row_range(int y, int rows);
160	    const Mat row_range(int y, int rows) const;
161	    Mat range(int x, int n);
162	    const Mat range(int x, int n) const;
163	
164	    // access raw data
165	    template<typename T> operator T*();
166	    template<typename T> operator const T*() const;
167	
168	    // convenient access float vec element
169	    float& operator[](int i);
170	    const float& operator[](int i) const;
171	
172	    // pointer to the data
173	    void* data;
174	
175	    // pointer to the reference counter
176	    // when points to user-allocated data, the pointer is NULL
177	    int* refcount;
178	
179	    // element size in bytes
180	    // 4 = float32/int32
181	    // 2 = float16
182	    // 1 = int8/uint8
183	    // 0 = empty
184	    size_t elemsize;
185	
186	    // the allocator
187	    Allocator* allocator;
188	
189	    // the dimensionality
190	    int dims;
191	
192	    int w;
193	    int h;
194	    int c;
195	
196	    size_t cstep;
197	};
198	
199	
200	inline Mat::Mat()
201	    : data(0), refcount(0), elemsize(0), allocator(0), dims(0), w(0), h(0), c(0), cstep(0)
202	{
203	}
204	
205	inline Mat::Mat(int _w, size_t _elemsize, Allocator* allocator)
206	    : data(0), refcount(0), dims(0)
207	{
208	    create(_w, _elemsize, allocator);
209	}
