217	inline Mat::Mat(int _w, int _h, int _c, size_t _elemsize, Allocator* allocator)
218	    : data(0), refcount(0), dims(0)
219	{
220	    create(_w, _h, _c, _elemsize, allocator);
221	}
222	
223	inline Mat::Mat(const Mat& m)
224	    : data(m.data), refcount(m.refcount), elemsize(m.elemsize), allocator(m.allocator), dims(m.dims)
225	{
226	    if (refcount)
227	        NCNN_XADD(refcount, 1);
228	
229	    w = m.w;
230	    h = m.h;
231	    c = m.c;
232	
233	    cstep = m.cstep;
234	}
