236	inline Mat::Mat(int _w, void* _data, size_t _elemsize, Allocator* _allocator)
237	    : data(_data), refcount(0), elemsize(_elemsize), allocator(_allocator), dims(1)
238	{
239	    w = _w;
240	    h = 1;
241	    c = 1;
242	
243	    cstep = w;
244	}
