246	inline Mat::Mat(int _w, int _h, void* _data, size_t _elemsize, Allocator* _allocator)
247	    : data(_data), refcount(0), elemsize(_elemsize), allocator(_allocator), dims(2)
248	{
249	    w = _w;
250	    h = _h;
251	    c = 1;
252	
253	    cstep = w * h;
254	}
255	
256	inline Mat::Mat(int _w, int _h, int _c, void* _data, size_t _elemsize, Allocator* _allocator)
257	    : data(_data), refcount(0), elemsize(_elemsize), allocator(_allocator), dims(3)
258	{
259	    w = _w;
260	    h = _h;
261	    c = _c;
262	
263	    cstep = alignSize(w * h * elemsize, 16) / elemsize;
264	}
265	
266	inline Mat::~Mat()
267	{
268	    release();
269	}
270	
271	inline Mat& Mat::operator=(const Mat& m)
272	{
273	    if (this == &m)
274	        return *this;
275	
276	    if (m.refcount)
277	        NCNN_XADD(m.refcount, 1);
278	
279	    release();
280	
281	    data = m.data;
282	    refcount = m.refcount;
283	    elemsize = m.elemsize;
284	    allocator = m.allocator;
285	
286	    dims = m.dims;
287	    w = m.w;
288	    h = m.h;
289	    c = m.c;
290	
291	    cstep = m.cstep;
292	
293	    return *this;
294	}
295	
296	inline Mat Mat::clone(Allocator* allocator) const
297	{
298	    if (empty())
299	        return Mat();
300	
301	    Mat m;
302	    if (dims == 1)
303	        m.create(w, elemsize, allocator);
304	    else if (dims == 2)
305	        m.create(w, h, elemsize, allocator);
306	    else if (dims == 3)
307	        m.create(w, h, c, elemsize, allocator);
308	
309	    if (total() > 0)
310	    {
311	        memcpy(m.data, data, total() * elemsize);
312	    }
313	
314	    return m;
315	}
316	
317	inline void Mat::create(int _w, size_t _elemsize, Allocator* _allocator)
318	{
319	    if (dims == 1 && w == _w && elemsize == _elemsize && allocator == _allocator)
320	        return;
321	
322	    release();
323	
324	    elemsize = _elemsize;
325	    allocator = _allocator;
326	
327	    dims = 1;
328	    w = _w;
329	    h = 1;
330	    c = 1;
331	
332	    cstep = w;
333	
334	    if (total() > 0)
335	    {
336	        size_t totalsize = alignSize(total() * elemsize, 4);
337	        if (allocator)
338	            data = allocator->fastMalloc(totalsize + (int)sizeof(*refcount));
339	        else
340	            data = fastMalloc(totalsize + (int)sizeof(*refcount));
341	        refcount = (int*)(((unsigned char*)data) + totalsize);
342	        *refcount = 1;
343	    }
344	}
