347	{
348	    if (dims == 2 && w == _w && h == _h && elemsize == _elemsize && allocator == _allocator)
349	        return;
350	
351	    release();
352	
353	    elemsize = _elemsize;
354	    allocator = _allocator;
355	
356	    dims = 2;
357	    w = _w;
358	    h = _h;
359	    c = 1;
360	
361	    cstep = w * h;
362	
363	    if (total() > 0)
364	    {
365	        size_t totalsize = alignSize(total() * elemsize, 4);
366	        if (allocator)
367	            data = allocator->fastMalloc(totalsize + (int)sizeof(*refcount));
368	        else
369	            data = fastMalloc(totalsize + (int)sizeof(*refcount));
370	        refcount = (int*)(((unsigned char*)data) + totalsize);
371	        *refcount = 1;
372	    }
373	}
374	
375	inline void Mat::create(int _w, int _h, int _c, size_t _elemsize, Allocator* _allocator)
376	{
377	    if (dims == 3 && w == _w && h == _h && c == _c && elemsize == _elemsize && allocator == _allocator)
378	        return;
379	
380	    release();
381	
382	    elemsize = _elemsize;
383	    allocator = _allocator;
384	
385	    dims = 3;
386	    w = _w;
387	    h = _h;
388	    c = _c;
389	
390	    cstep = alignSize(w * h * elemsize, 16) / elemsize;
391	
392	    if (total() > 0)
393	    {
394	        size_t totalsize = alignSize(total() * elemsize, 4);
395	        if (allocator)
396	            data = allocator->fastMalloc(totalsize + (int)sizeof(*refcount));
397	        else
398	            data = fastMalloc(totalsize + (int)sizeof(*refcount));
399	        refcount = (int*)(((unsigned char*)data) + totalsize);
400	        *refcount = 1;
401	    }
402	}
403	
404	inline void Mat::addref()
405	{
406	    if (refcount)
407	        NCNN_XADD(refcount, 1);
408	}
409	
410	inline void Mat::release()
411	{
412	    if (refcount && NCNN_XADD(refcount, -1) == 1)
413	    {
414	        if (allocator)
415	            allocator->fastFree(data);
416	        else
417	            fastFree(data);
418	    }
419	
420	    data = 0;
421	
422	    elemsize = 0;
423	
424	    dims = 0;
425	    w = 0;
426	    h = 0;
427	    c = 0;
428	
429	    cstep = 0;
430	
431	    refcount = 0;
432	}
433	
434	inline bool Mat::empty() const
435	{
436	    return data == 0 || total() == 0;
437	}
438	
439	inline size_t Mat::total() const
440	{
441	    return cstep * c;
442	}
443	
444	inline Mat Mat::channel(int c)
445	{
446	    return Mat(w, h, (unsigned char*)data + cstep * c * elemsize, elemsize, allocator);
447	}
448	
449	inline const Mat Mat::channel(int c) const
450	{
451	    return Mat(w, h, (unsigned char*)data + cstep * c * elemsize, elemsize, allocator);
452	}
453	
454	inline float* Mat::row(int y)
455	{
456	    return (float*)data + w * y;
457	}
