23	static int get_topk(const std::vector<float>& cls_scores, unsigned int topk, std::vector< std::pair<float, int> >& top_list)
24	{
25	    if (cls_scores.size() < topk) topk = cls_scores.size();
26	
27	    int size = cls_scores.size();
28	    std::vector< std::pair<float, int> > vec;
29	    vec.resize(size);
30	    for (int i=0; i<size; i++)
31	    {
32	        vec[i] = std::make_pair(cls_scores[i], i);
33	    }
34	
35	    std::partial_sort(vec.begin(), vec.begin() + topk, vec.end(),
36	                      std::greater< std::pair<float, int> >());
37	
38	    top_list.resize(topk);
39	    for (unsigned int i=0; i<topk; i++)
40	    {
41	        top_list[i].first = vec[i].first;
42	        top_list[i].second = vec[i].second;
43	    }
44	    vec.clear();
45	
46	    return 0;
47	}
