49	int get_topk(ncnn::Mat& result , int topk, std::vector< std::pair<float, int> >& top_list)
50	{
51	    std::vector<float> cls_scores;
52	    cls_scores.resize(result.c*result.h*result.w);
53	
54	    int i = 0;
55	    for (int c = 0; c < result.c; c++)
56	    {
57	        float *ptrf = (float*)result.channel(c).data;
58	        for (int hw = 0; hw < result.h * result.w; hw++)
59	        {
60	            cls_scores[i++] = *ptrf++;
61	        }
62	    }
63	
64	    get_topk(cls_scores, topk, top_list);
65	    cls_scores.clear();
66	    return 0;
67	}
